function cleanDashboard(){const records=savedData(),stages=[['Opportunities',records.filter(r=>r.form==='Contract Opportunities').length],['Qualified',records.filter(r=>r.form==='Contract Opportunities'&&r['Qualification decision']==='Qualified').length],['Estimates',records.filter(r=>r.form==='Cost Estimation & Scenarios').length],['Awards',records.filter(r=>r.form==='Award / Loss Register'&&r.Outcome==='Awarded').length],['Projects',records.filter(r=>r.form==='Awarded Projects').length],['Receipts',records.filter(r=>r.form==='Cash Receipts & Payments').length]],recent=records.slice().sort((a,b)=>new Date(b.updatedAt||b.createdAt)-new Date(a.updatedAt||a.createdAt)).slice(0,8);return `<div class="hero-row"><div><h1>Executive Dashboard</h1><p>Live operational position from saved company transactions.</p></div></div><div class="demo-notice"><b>Live data:</b> Figures below are calculated only from records entered into MUSTAQEEM.</div><div class="kpi-grid">${kpi('Awarded contract value','â€”','â†—','LIVE')}${kpi('Recorded operating cost','SAR 0','â—«','LIVE')}${kpi('Open receivables','SAR 0','â—‰','LIVE')}${kpi('Contract opportunities','0','âœ“','LIVE')}</div><article class="card lifecycle-card"><div class="card-title"><div><p class="section-eyebrow">RECORDED WORKFLOW</p><h3>Business lifecycle</h3></div></div><div class="lifecycle-flow">${stages.map((stage,index)=>`${index?'<span class="flow-arrow">â†’</span>':''}<div class="flow-stage slate"><b>${stage[1]}</b><strong>${stage[0]}</strong><small>Saved records</small></div>`).join('')}</div></article><article class="card"><div class="card-title"><div><p class="section-eyebrow">AUDIT TRAIL</p><h3>Recent saved transactions</h3></div><span class="badge">${recent.length} records</span></div><div class="table-wrap"><table><thead><tr><th>DOCUMENT</th><th>SECTION</th><th>FORM</th><th>DATE</th></tr></thead><tbody>${recent.length?recent.map(r=>`<tr><td><b>${r['Document Number']||'â€”'}</b></td><td>${titles[r.module]?.[1]||r.module||'â€”'}</td><td>${r.form||'â€”'}</td><td>${r.updatedAt||r.createdAt?new Date(r.updatedAt||r.createdAt).toLocaleDateString():'â€”'}</td></tr>`).join(''):'<tr><td colspan="4"><div class="empty-state">No transactions have been entered. Start by adding a Contract Opportunity.</div></td></tr>'}</tbody></table></div></article>`}
