function dashboardGraphs(){const records=savedData(),projects=projectOverviewRows(),budgets=projects.map(p=>[p.name,p.budget,p.actual]),statuses=projects.reduce((all,p)=>{all[p.status]=(all[p.status]||0)+1;return all},{}),marketing=marketingOverviewData(),funnel=[['Opportunities',marketing.opportunities.length],['Qualified',marketing.opportunities.filter(r=>r['Qualification decision']==='Qualified').length],['Estimates',marketing.estimates.length],['Bid decisions',marketing.decisions.length],['Proposals',marketing.proposals.length],['Awards',marketing.outcomes.filter(r=>r.Outcome==='Awarded').length]],revenue=records.filter(r=>r.form==='Revenue YTD').reduce((s,r)=>s+Number(r['Revenue to recognize (SAR)']||0),0),receipts=records.filter(r=>r.form==='Cash Receipts & Payments'&&r['Transaction type']==='Customer Receipt').reduce((s,r)=>s+Number(r['Amount (SAR)']||0),0),receivables=records.filter(r=>r.form==='Accounts Receivable'&&!/Paid|Cancelled/i.test(r.Status||'')),today=new Date(),aging=[['Current',0],['1â€“30 days',0],['31â€“60 days',0],['61â€“90 days',0],['Over 90 days',0]];receivables.forEach(r=>{const amount=Number(r['Total including VAT (SAR)']||0),due=r['Due date']?new Date(r['Due date']):today,days=Math.floor((today-due)/86400000),index=days<=0?0:days<=30?1:days<=60?2:days<=90?3:4;aging[index][1]+=amount});const baseline=records.filter(r=>r.form==='Baseline Budgets'),costs=[['Materials',baseline.reduce((s,r)=>s+Number(r['Material budget (SAR)']||0),0)],['Manpower',baseline.reduce((s,r)=>s+Number(r['Manpower budget (SAR)']||0),0)],['Subcontractors',baseline.reduce((s,r)=>s+Number(r['Subcontractor budget (SAR)']||0),0)],['Equipment',baseline.reduce((s,r)=>s+Number(r['Equipment budget (SAR)']||0),0)],['Overhead',baseline.reduce((s,r)=>s+Number(r['Overhead budget (SAR)']||0),0)]],payments=records.filter(r=>r.form==='Cash Receipts & Payments'&&r['Transaction type']!=='Customer Receipt').reduce((s,r)=>s+Number(r['Amount (SAR)']||0),0),forecasts=records.filter(r=>r.form==='Cash Forecast'),forecastIn=forecasts.filter(r=>r['Cash-flow type']==='Receipt').reduce((s,r)=>s+Number(r['Expected amount (SAR)']||0)*Number(r['Probability (%)']||100)/100,0),forecastOut=forecasts.filter(r=>r['Cash-flow type']!=='Receipt').reduce((s,r)=>s+Number(r['Expected amount (SAR)']||0)*Number(r['Probability (%)']||100)/100,0);return `<div class="dashboard-graphs"><article class="card graph-card"><div class="card-title"><h3>Budget vs Recorded Cost</h3><span class="badge">Live</span></div>${budgets.some(x=>x[1]||x[2])?`<div class="project-compare">${budgets.map(p=>`<div><b>${p[0]}</b><div class="dual-bars"><i style="width:${p[1]?100:0}%"></i><i class="actual" style="width:${p[1]?Math.min(p[2]/p[1]*100,100):0}%"></i></div><small>${compactMoney(p[1])} budget Â· ${compactMoney(p[2])} recorded</small></div>`).join('')}</div>`:graphEmpty('Create a baseline budget and record project costs.')}</article><article class="card graph-card"><div class="card-title"><h3>Project Health</h3><span class="badge">Live</span></div>${projects.length?`<div class="health-chart"><div class="health-total"><b>${projects.length}</b><span>Projects</span></div><div>${Object.entries(statuses).map(([status,count])=>`<p><i></i>${status}<b>${count}</b></p>`).join('')}</div></div>`:graphEmpty('Award a contract to create the first project.')}</article><article class="card graph-card"><div class="card-title"><h3>Opportunity Funnel</h3><span class="badge">Live</span></div>${funnel[0][1]?`<div class="funnel-chart">${funnel.map((item,index)=>`<div style="width:${100-index*9}%"><span>${item[0]}</span><b>${item[1]}</b></div>`).join('')}</div>`:graphEmpty('Add a contract opportunity to begin the funnel.')}</article><article class="card graph-card"><div class="card-title"><h3>Revenue vs Receipts</h3><span class="badge">Live</span></div>${revenue||receipts?graphBars([['Recognized revenue',revenue],['Customer receipts',receipts]]):graphEmpty('Post revenue recognition and customer receipts.')}</article><article class="card graph-card"><div class="card-title"><h3>Receivables Ageing</h3><span class="badge">Live</span></div>${receivables.length?graphBars(aging):graphEmpty('Post customer invoices to build receivables ageing.')}</article><article class="card graph-card"><div class="card-title"><h3>Budget Cost Breakdown</h3><span class="badge">Live</span></div>${costs.some(x=>x[1])?graphBars(costs):graphEmpty('Create a project baseline budget with cost categories.')}</article><article class="card graph-card graph-wide"><div class="card-title"><h3>Cash Flow Position</h3><span class="badge">Live</span></div>${receipts||payments||forecastIn||forecastOut?graphBars([['Actual receipts',receipts],['Actual payments',payments],['Forecast receipts',forecastIn],['Forecast payments',forecastOut]]):graphEmpty('Enter receipts, payments or cash-flow forecast lines.')}</article></div>`}
