function projectTable(rows){return `<div class="table-wrap"><table><thead><tr><th>PROJECT</th><th>CONTRACT VALUE</th><th>PROGRESS</th><th>STATUS</th></tr></thead><tbody>${rows.map(p=>`<tr data-action><td><div class="project-cell"><span>${p.name.charAt(0)}</span><div><b>${p.name}</b><small>${p.code} â€¢ ${p.client}</small></div></div></td><td>${p.value}</td><td><div style="display:flex;align-items:center;gap:8px"><div class="progress"><i style="width:${p.progress}%"></i></div>${p.progress}%</div></td><td><span class="badge ${p.status==='Attention'?'amber':p.status==='Delayed'?'red':''}">${p.status}</span></td></tr>`).join('')}</tbody></table></div>`}
