function operationalRecords(form){return savedWorkflowRecords().filter(r=>r.module==='operations'&&(!form||r.form===form))}
function replaceOperationalField(name,records,value,label,placeholder='Select a linked recordâ€¦'){const original=document.querySelector(`[name="${name}"]`);if(!original)return null;const select=document.createElement('select');select.name=name;select.required=original.required;select.innerHTML=`<option value="">${records.length?placeholder:'No eligible linked record available'}</option>${records.map(r=>`<option value="${value(r)}">${label(r)}</option>`).join('')}`;original.replaceWith(select);select.closest('label')?.insertAdjacentHTML('beforeend','<small class="field-help">Linked to a saved upstream operational record.</small>');return select}
function insertOperationalSource(name,title,records,label){const host=document.getElementById('formFields'),first=host?.querySelector('label');if(!host)return null;const wrapper=document.createElement('label');wrapper.className='wide operational-link';wrapper.innerHTML=`${title}<select name="${name}" ${records.length?'required':''}><option value="">${records.length?'Select source documentâ€¦':'No eligible source document available'}</option>${records.map(r=>`<option value="${r['Document Number']}">${label(r)}</option>`).join('')}</select><small class="field-help">Values are copied from the selected upstream document.</small>`;first?.after(wrapper);return wrapper.querySelector('select')}
function awardedProjectOptions(){return awardedProjectRecords().map(r=>({id:r['Document Number'],label:`${r['Project code']||r['Document Number']} â€” ${r['Project name']||'Awarded project'}`,record:r}))}
function linkOperationalProject(fieldName='Project'){const projects=awardedProjectOptions(),select=replaceOperationalField(fieldName,projects,p=>p.id,p=>p.label,'Select an awarded projectâ€¦');return {select,projects}}
function configurePurchaseChain(){const stage=document.querySelector('[name="Stage"]'),records=operationalRecords('Purchase Cycle'),order=['Purchase Requisition','Request for Quotation','Purchase Order','Goods Receipt','Supplier Invoice','Payment Request'],source=insertOperationalSource('Source purchase document','Previous purchase-cycle document',[],r=>r['Document Number']);if(!stage||!source)return;const refresh=()=>{const index=order.indexOf(stage.value),required=index>0?order[index-1]:null,used=new Set(records.filter(r=>r.Stage===stage.value).map(r=>r['Source purchase document'])),eligible=required?records.filter(r=>r.Stage===required&&!used.has(r['Document Number'])):[];source.closest('label').hidden=!required;source.required=Boolean(required);source.innerHTML=`<option value="">${eligible.length?'Select previous-stage documentâ€¦':required?`No unused ${required} document available`:'Not required for requisition'}</option>${eligible.map(r=>`<option value="${r['Document Number']}">${r['Document Number']} â€” ${r['Item / service']||r.Supplier||required}</option>`).join('')}`};stage.addEventListener('change',refresh);source.addEventListener('change',()=>{const record=records.find(r=>r['Document Number']===source.value);if(!record)return;['Project','Reference number','Supplier','Item / service','Quantity','Amount (SAR)'].forEach(name=>setFormValue(name,record[name]))});refresh()}
function configureOperationalLinks(key){if(key==='Revenue & CRM Cycle'){linkOperationalProject('Project');return}if(key==='Billing & Collections'){const rows=operationalRecords('Revenue & CRM Cycle'),used=new Set(operationalRecords('Billing & Collections').map(r=>r['Source revenue document'])),eligible=rows.filter(r=>!used.has(r['Document Number'])),source=insertOperationalSource('Source revenue document','Revenue / customer source',eligible,r=>`${r['Document Number']} â€” ${r.Customer||r.Transaction}`);source?.addEventListener('change',()=>{const record=rows.find(r=>r['Document Number']===source.value);if(!record)return;setFormValue('Customer',record.Customer);setFormValue('Project',record.Project);setFormValue('Amount (SAR)',record['Amount (SAR)']);setFormValue('Invoice / receipt number',record['Document number']||record['Document Number'])});return}if(key==='Purchase Cycle'){linkOperationalProject('Project');configurePurchaseChain();return}if(key==='HRM & Manpower'){linkOperationalProject('Project / department');return}if(key==='Attendance & Payroll'){const employees=operationalRecords('HRM & Manpower').filter(r=>/Hired|Mobilized|Active/i.test(r.Status||'')),select=replaceOperationalField('Employee',employees,r=>r['Employee number']||r['Document Number'],r=>`${r['Employee number']||r['Document Number']} â€” ${r['Employee / position']}`,'Select an active employeeâ€¦');select?.addEventListener('change',()=>{const employee=employees.find(r=>(r['Employee number']||r['Document Number'])===select.value);if(!employee)return;setFormValue('Project',employee['Project / department']);setFormValue('Basic salary (SAR)',employee['Basic salary (SAR)'])});return}if(key==='Inventory Management'){const receipts=operationalRecords('Purchase Cycle').filter(r=>['Goods Receipt','Supplier Invoice'].includes(r.Stage)),source=insertOperationalSource('Source receipt / purchase document','Goods receipt / purchase source',receipts,r=>`${r['Document Number']} â€” ${r['Item / service']||r.Supplier}`);source?.addEventListener('change',()=>{const record=receipts.find(r=>r['Document Number']===source.value);if(!record)return;setFormValue('Reference number',record['Reference number']||record['Document Number']);setFormValue('Project',record.Project);setFormValue('Item code / description',record['Item / service']);setFormValue('Quantity',record.Quantity);const quantity=Number(record.Quantity||0);setFormValue('Unit cost (SAR)',quantity?Number(record['Amount (SAR)']||0)/quantity:0)});return}if(key==='Fixed Assets'){linkOperationalProject('Project / location');return}if(key==='Site & Other Expenses')linkOperationalProject('Project')}
const openFormOperationalLinksCore=openForm;
openForm=function(page=currentPage,key=''){openFormOperationalLinksCore(page,key);if(page==='operations')configureOperationalLinks(key)};
function scenarioAnalysisPanel(){const estimates=savedCostEstimates();return `<article class="card whatif-panel"><div class="card-title"><div><p class="section-eyebrow">NON-POSTING ANALYSIS</p><h3>Contract What-if Scenario Analysis</h3><p>Change temporary costs to test different situations. The saved cost estimate will not be changed.</p></div><span class="badge amber">Simulation only</span></div>${estimates.length?`<div class="whatif-toolbar"><label>Contract / saved estimate<select id="whatIfContract">${estimates.map((r,i)=>`<option value="${i}">${r['Document Number']} â€” ${r['Estimate title / scope package']||r['Select qualified contract']}</option>`).join('')}</select></label><button id="resetWhatIf" class="action-btn">Reset to saved estimate</button></div><div id="whatIfWorkspace"></div>`:'<div class="empty-state">Save a Cost Estimation first to use scenario analysis.</div>'}</article>`}
function renderWhatIfWorkspace(index=0){const estimates=savedCostEstimates(),record=estimates[Number(index)];if(!record)return;const host=document.getElementById('whatIfWorkspace'),revenue=Number(record['Expected contract revenue (SAR)']||0);host.innerHTML=`<div class="whatif-summary"><span>Saved base estimate <b data-saved-base>SAR ${Number(record['Base estimated cost (SAR)']||0).toLocaleString()}</b></span><span>Expected revenue <b>SAR ${revenue.toLocaleString()}</b></span><span class="simulation-flag">Temporary working values</span></div><div class="whatif-cost-grid">${scenarioCostComponents.map((name,i)=>`<label>${name.replace(' (SAR)','')}<input type="number" min="0" step="any" data-whatif-cost="${i}" value="${Number(record[name]||0)}"><small>Saved: SAR ${Number(record[name]||0).toLocaleString()}</small></label>`).join('')}</div><div class="whatif-scenarios">${[['Worse',10,'Increase'],['Normal',0,'Adjustment'],['Good',8,'Saving']].map(([name,pct,word])=>`<section class="whatif-card ${name.toLowerCase()}" data-scenario="${name}"><h4>${name} Case</h4><div class="scenario-controls"><label>${word} %<input type="number" step="any" data-scenario-pct value="${pct}"></label><label>${word} amount (SAR)<input type="number" step="any" data-scenario-amount value="0"></label></div><dl><div><dt>Estimated cost</dt><dd data-result-cost>â€”</dd></div><div><dt>Forecast profit</dt><dd data-result-profit>â€”</dd></div><div><dt>Forecast margin</dt><dd data-result-margin>â€”</dd></div></dl></section>`).join('')}</div><p class="whatif-note">These values are for viewing and decision support only. They are not saved and do not modify document ${record['Document Number']}.</p>`;bindWhatIfCalculator()}
function bindWhatIfCalculator(){const host=document.getElementById('whatIfWorkspace');if(!host)return;const costInputs=[...host.querySelectorAll('[data-whatif-cost]')],cards=[...host.querySelectorAll('[data-scenario]')],contractIndex=document.getElementById('whatIfContract').value,record=savedCostEstimates()[Number(contractIndex)],revenue=Number(record['Expected contract revenue (SAR)']||0),number=input=>Number(input.value||0),money=value=>`SAR ${value.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}`;const calculateCard=(card,source='pct')=>{const base=costInputs.reduce((sum,input)=>sum+number(input),0),pct=card.querySelector('[data-scenario-pct]'),amount=card.querySelector('[data-scenario-amount]'),isGood=card.dataset.scenario==='Good';if(source==='amount')pct.value=base?((number(amount)/base)*100).toFixed(2):'0.00';else amount.value=(base*number(pct)/100).toFixed(2);const cost=Math.max(0,base+(isGood?-1:1)*number(amount)),profit=revenue-cost,margin=revenue?profit/revenue*100:0;card.querySelector('[data-result-cost]').textContent=money(cost);card.querySelector('[data-result-profit]').textContent=money(profit);card.querySelector('[data-result-margin]').textContent=`${margin.toFixed(2)}%`};const calculateAll=()=>cards.forEach(card=>calculateCard(card,'pct'));costInputs.forEach(input=>input.addEventListener('input',calculateAll));cards.forEach(card=>{card.querySelector('[data-scenario-pct]').addEventListener('input',()=>calculateCard(card,'pct'));card.querySelector('[data-scenario-amount]').addEventListener('input',()=>calculateCard(card,'amount'))});calculateAll()}
function bindScenarioPanel(){const selector=document.getElementById('whatIfContract'),reset=document.getElementById('resetWhatIf');if(!selector)return;selector.addEventListener('change',()=>renderWhatIfWorkspace(selector.value));reset.addEventListener('click',()=>renderWhatIfWorkspace(selector.value));renderWhatIfWorkspace(selector.value)}
function alignMarketingWorkflow(page,view){if(page!=='marketing')return;content.querySelector('[data-new-form]')?.remove();if(view!=='forms')return;const qualification=content.querySelector('[data-form-key="Qualification Review"]');if(qualification){qualification.querySelector('.badge').textContent='Approval step';qualification.querySelector('p').textContent='Director reviews the submitted opportunity and selects Qualified, Return or Not Qualified.';qualification.querySelector('footer span').textContent='Open approval centre â†’'}const proposal=content.querySelector('[data-form-key="Proposal & Submission"]');if(proposal)proposal.querySelector('p').textContent='Prepare, approve and submit the technical and commercial bidding proposal.';['Cost Estimation & Scenarios','Bid / No-Bid Decision','Proposal & Submission','Award / Loss Register'].forEach(key=>{const card=content.querySelector(`[data-form-key="${key}"]`),gate=marketingGate(key);if(!card||!gate)return;card.querySelector('.badge').textContent=gate.count?'Ready':'Waiting';card.querySelector('footer b').textContent=`${gate.count} eligible`;card.classList.toggle('workflow-locked',!gate.count);if(!gate.count)card.title=gate.message})}
function closeQuickPanel(){quickPanel.classList.add('hidden');delete quickPanel.dataset.panel}
function showSearch(){quickPanelLabel.textContent='GLOBAL SEARCH';quickPanelTitle.textContent='Find a page or transaction';quickPanelBody.innerHTML=`<div class="quick-search"><input id="quickSearchInput" placeholder="Search modules, forms or recordsâ€¦" autocomplete="off"></div><div id="quickResults" class="quick-results"></div>`;quickPanel.classList.remove('hidden');const input=document.getElementById('quickSearchInput'),results=document.getElementById('quickResults');const draw=()=>{const q=input.value.trim().toLowerCase(),matches=searchIndex.filter(x=>!q||`${x[1]} ${x[2]}`.toLowerCase().includes(q));results.innerHTML=matches.length?matches.map(x=>`<button class="quick-result" data-page="${x[0]}"><b>${x[1]}</b><small>${x[2]}</small></button>`).join(''):'<div class="panel-empty">No matching page found.</div>'};input.addEventListener('input',draw);draw();setTimeout(()=>input.focus(),30)}
function showNotifications(){quickPanelLabel.textContent='ACTION CENTRE';quickPanelTitle.textContent='Notifications';quickPanelBody.innerHTML=`<div class="notification-list"><button class="notification-item unread" data-page="approvals"><b>7 approvals require review</b><small>Purchase orders, payments and budget revisions</small></button><button class="notification-item unread" data-page="accounts"><b>3 supplier invoices need matching</b><small>PO and GRN verification is pending</small></button><button class="notification-item" data-page="marketing"><b>Bid submission due in 2 days</b><small>Riyadh Commercial Complex</small></button><button class="notification-item" data-page="projectcosting"><b>Budget variance requires attention</b><small>Metro Station Fit-out</small></button></div>`;quickPanel.classList.remove('hidden')}
function showSettings(){const setups=[['Company Setup','Legal entity and Saudi registrations'],['Users & Access','Create users, assign roles, companies and permissions'],['Creditors / Suppliers','Supplier master and payment controls'],['Buyers / Customers','Customer master and billing controls','Debtors / Customers'],['Bank Accounts','Company bank and IBAN master'],['Projects & Cost Centres','Project and cost allocation setup'],['Chart of Accounts Setup','Ledger accounts and Excel import'],['Tax Codes','Saudi VAT and tax treatments'],['Currencies','Transaction currencies and rates'],['Payment Terms','Customer and supplier payment terms']];quickPanelLabel.textContent='MASTER DATA';quickPanelTitle.textContent='Settings & Setups';quickPanelBody.innerHTML=`<div class="notification-list">${setups.map(x=>`<button class="notification-item" data-setup-form="${x[0]}"><b>${x[2]||x[0]}</b><small>${x[1]}</small></button>`).join('')}</div>`;quickPanel.classList.remove('hidden')}
function toggleQuickPanel(panel,openPanel){
 const isCurrent=!quickPanel.classList.contains('hidden')&&quickPanel.dataset.panel===panel;
 if(isCurrent){closeQuickPanel();return}
 openPanel();quickPanel.dataset.panel=panel;
}
const globalSearchButton=document.getElementById('globalSearch');
const notificationsButton=document.getElementById('notifications');
const settingsButton=document.getElementById('settingsShortcut');
globalSearchButton.addEventListener('click',()=>toggleQuickPanel('search',showSearch));
notificationsButton.addEventListener('click',()=>toggleQuickPanel('notifications',showNotifications));
settingsButton.addEventListener('click',()=>toggleQuickPanel('settings',showSettings));
document.getElementById('closeQuickPanel').addEventListener('click',closeQuickPanel);
quickPanel.addEventListener('click',e=>{const setup=e.target.closest('[data-setup-form]');if(setup){closeQuickPanel();openForm('settings',setup.dataset.setupForm);document.getElementById('entryForm').dataset.module='settings'}if(e.target.closest('[data-page]'))setTimeout(closeQuickPanel,0)});
document.addEventListener('click',e=>{
 if(quickPanel.classList.contains('hidden'))return;
 if(quickPanel.contains(e.target)||e.target.closest('#globalSearch, #notifications, #settingsShortcut'))return;
 closeQuickPanel();
});
document.addEventListener('keydown',e=>{if(e.key==='Escape')closeQuickPanel()});
function updateRoleNavigation(){const director=currentRole==='Director',accounting=director||currentRole==='Accountant';document.querySelector('[data-page="approvals"]').hidden=!director;document.querySelector('[data-marketing-form="Qualification Review"]').hidden=!director;document.querySelector('.accounts-nav-group').hidden=!accounting;document.querySelector('.finance-nav-group').hidden=!accounting}
document.getElementById('signIn').onclick=()=>{currentRole=document.getElementById('loginRole').value;initializeCleanDataset();document.getElementById('login').classList.add('hidden');document.getElementById('app').classList.remove('hidden');const roleName=currentRole==='Director'?'Director':currentRole==='Accountant'?'Accountant':'Marketing User',initials=currentRole==='Director'?'DR':currentRole==='Accountant'?'AC':'MU';document.querySelector('.side-footer b').textContent=roleName;document.querySelector('.side-footer small').textContent=currentRole;document.querySelector('.side-footer>span').textContent=initials;updateRoleNavigation();refreshCompanySwitcher();render(currentRole==='Director'?'approvals':currentRole==='Accountant'?'accounts':'marketing','overview')};
document.getElementById('companySwitcher').addEventListener('change',e=>{localStorage.setItem('mustaqeem-active-company',e.target.value);e.target.classList.remove('company-changed');void e.target.offsetWidth;e.target.classList.add('company-changed');toast(`Active company changed to ${e.target.value}`)});
document.getElementById('logout').onclick=()=>{document.getElementById('app').classList.add('hidden');document.getElementById('login').classList.remove('hidden')};
