function savedData(){return JSON.parse(localStorage.getItem('mustaqeem-demo-records')||'[]')}
function numeric(record,names){for(const name of names){const value=Number(record?.[name]);if(Number.isFinite(value)&&value)return value}return 0}
function compactMoney(value){const n=Number(value||0);return n>=1000000?`SAR ${(n/1000000).toFixed(n%1000000?1:0)}M`:n>=1000?`SAR ${(n/1000).toFixed(n%1000?1:0)}K`:`SAR ${n.toLocaleString()}`}
function updateKpiCards(values){document.querySelectorAll('.kpi-card').forEach((card,index)=>{const item=values[index];if(!item)return;card.querySelector('.kpi-head span:first-child').textContent=item[0];card.querySelector('h3').textContent=item[1];const trend=card.querySelector('.trend');if(trend)trend.innerHTML=`<b>${item[2]||'LIVE'}</b> ${item[3]||'from saved records'}`})}
function marketingOverviewData(){const records=savedData(),opportunities=records.filter(r=>r.form==='Contract Opportunities'),estimates=records.filter(r=>r.form==='Cost Estimation & Scenarios'),decisions=records.filter(r=>r.form==='Bid / No-Bid Decision'),proposals=records.filter(r=>r.form==='Bid Proposals'),outcomes=records.filter(r=>r.form==='Award / Loss Register'),bidValue=decisions.filter(r=>r.Decision==='Approved to Bid').reduce((sum,r)=>sum+Number(r['Recommended bid value (SAR)']||0),0),weightedBase=decisions.reduce((sum,r)=>sum+Number(r['Recommended bid value (SAR)']||0),0),weightedProfit=decisions.reduce((sum,r)=>sum+Number(r['Forecast profit (SAR)']||0),0);return {records,opportunities,estimates,decisions,proposals,outcomes,kpis:[['Opportunities',String(opportunities.length),'LIVE'],['Cost estimates',String(estimates.length),'LIVE'],['Approved bid value',compactMoney(bidValue),'LIVE'],['Forecast margin',weightedBase?`${(weightedProfit/weightedBase*100).toFixed(1)}%`:'â€”','LIVE']]}}
function workflowStage(opportunity,data){const id=opportunity['Document Number'],estimate=data.estimates.find(r=>r['Select qualified contract']===id),decision=data.decisions.find(r=>r['Contract opportunity reference']===id),proposal=data.proposals.find(r=>r['Contract opportunity reference']===id),outcome=data.outcomes.find(r=>r['Select submitted proposal']===proposal?.['Document Number']);if(outcome)return outcome.Outcome==='Awarded'?'Awarded':`Closed â€” ${outcome.Outcome}`;if(proposal)return proposal['Proposal status']||'Proposal';if(decision)return decision.Decision||'Bid Decision';if(estimate)return 'Estimation';if(opportunity['Qualification decision']==='Qualified')return 'Qualified';return 'Qualification'}
function accurateOpportunityPipeline(){const data=marketingOverviewData(),rows=data.opportunities;return `<article class="card opportunity-pipeline"><div class="card-title"><div><p class="section-eyebrow">LIVE WORKFLOW</p><h3>Opportunity Pipeline</h3></div><span class="badge">${rows.length} records</span></div><div class="table-wrap"><table><thead><tr><th>DOCUMENT</th><th>OPPORTUNITY</th><th>CLIENT</th><th>STAGE</th><th>EST. VALUE</th><th>QUALIFICATION</th></tr></thead><tbody>${rows.length?rows.map(r=>`<tr><td><b>${r['Document Number']}</b></td><td>${r['Opportunity title']}</td><td>${r['Prospective client']}</td><td><span class="badge">${workflowStage(r,data)}</span></td><td>${compactMoney(r['Estimated contract value (SAR)'])}</td><td>${r['Qualification decision']||'Pending'}</td></tr>`).join(''):'<tr><td colspan="6"><div class="empty-state">No contract opportunities have been recorded.</div></td></tr>'}</tbody></table></div></article>`}
function projectOverviewRows(){const records=savedData(),awards=records.filter(r=>r.module==='projectcosting'&&r.form==='Awarded Projects');return awards.map(award=>{const id=award['Document Number'],baseline=records.filter(r=>r.form==='Baseline Budgets'&&r.Project===id).at(-1),operations=records.filter(r=>r.module==='operations'&&(r.Project===id||r['Project / department']===id||r['Project / location']===id)),budget=baseline?['Material budget (SAR)','Manpower budget (SAR)','Subcontractor budget (SAR)','Equipment budget (SAR)','Overhead budget (SAR)','Contingency (SAR)'].reduce((s,k)=>s+Number(baseline[k]||0),0):0,actual=operations.reduce((sum,r)=>sum+numeric(r,['Amount (SAR)','Acquisition cost (SAR)','Basic salary (SAR)']),0);return {code:award['Project code']||id,name:award['Project name']||id,contract:Number(award['Contract value (SAR)']||0),budget,actual,committed:0,variance:budget-actual,status:award['Project status']||'Awarded'}})}
function accurateProjectPortfolio(selected='all'){let rows=projectOverviewRows();if(selected!=='all')rows=rows.filter(r=>r.code===selected);return `<article class="card portfolio-control"><div class="card-title"><div><p class="section-eyebrow">SAVED PROJECT RECORDS</p><h3>Project Portfolio</h3></div><span class="badge">${rows.length} projects</span></div><div class="table-wrap"><table><thead><tr><th>PROJECT</th><th>CONTRACT</th><th>BASELINE</th><th>RECORDED COST</th><th>VARIANCE</th><th>STATUS</th></tr></thead><tbody>${rows.length?rows.map(p=>`<tr><td><b>${p.name}</b><br><small>${p.code}</small></td><td>${compactMoney(p.contract)}</td><td>${p.budget?compactMoney(p.budget):'Not created'}</td><td>${compactMoney(p.actual)}</td><td class="${p.variance<0?'variance-negative':'variance-positive'}">${p.budget?compactMoney(p.variance):'â€”'}</td><td><span class="badge">${p.status}</span></td></tr>`).join(''):'<tr><td colspan="6"><div class="empty-state">No awarded projects have entered Projects & Costing yet.</div></td></tr>'}</tbody></table></div></article>`}
function operationsOverviewSummary(){const records=savedData().filter(r=>r.module==='operations'),groups=moduleInfo.operations.map(item=>{const rows=records.filter(r=>r.form===item[0]),value=rows.reduce((sum,r)=>sum+numeric(r,['Amount (SAR)','Acquisition cost (SAR)','Basic salary (SAR)','Unit cost (SAR)']),0);return {name:item[0],count:rows.length,value}});return `<article class="card overview-record-summary"><div class="card-title"><div><p class="section-eyebrow">SAVED TRANSACTIONS</p><h3>Operational register summary</h3></div><span class="badge">${records.length} entries</span></div><div class="table-wrap"><table><thead><tr><th>PROCESS</th><th>RECORDS</th><th>RECORDED VALUE</th><th>STATUS</th></tr></thead><tbody>${groups.map(g=>`<tr><td><b>${g.name}</b></td><td>${g.count}</td><td>${g.value?compactMoney(g.value):'â€”'}</td><td><span class="badge">${g.count?'Active':'No data'}</span></td></tr>`).join('')}</tbody></table></div></article>`}
function controlOverviewSummary(page){const records=savedData().filter(r=>r.module===page),groups=moduleInfo[page].map(item=>{const rows=records.filter(r=>r.form===item[0]),value=rows.reduce((sum,r)=>sum+numeric(r,['Total including VAT (SAR)','Amount (SAR)','Forecast revenue (SAR)','Forecast cost (SAR)','Outstanding amount (SAR)','Expected amount (SAR)','Debit amount (SAR)','Credit amount (SAR)']),0),latest=rows.map(r=>r.updatedAt||r.createdAt).filter(Boolean).sort().at(-1);return{name:item[0],count:rows.length,value,latest}});return `<article class="card overview-record-summary"><div class="card-title"><div><p class="section-eyebrow">SAVED TRANSACTIONS</p><h3>${page==='accounts'?'Accounting':'Finance'} register summary</h3></div><span class="badge">${records.length} entries</span></div><div class="table-wrap"><table><thead><tr><th>REGISTER</th><th>RECORDS</th><th>RECORDED VALUE</th><th>LATEST UPDATE</th></tr></thead><tbody>${groups.map(g=>`<tr><td><b>${g.name}</b></td><td>${g.count}</td><td>${g.value?compactMoney(g.value):'â€”'}</td><td>${g.latest?new Date(g.latest).toLocaleDateString():'No data'}</td></tr>`).join('')}</tbody></table></div></article>`}
function overviewMetric(label,value,detail,icon){return `<article class="card kpi-card"><div class="kpi-head"><span>${label}</span><span class="kpi-icon">${icon}</span></div><h3>${value}</h3><div class="trend"><b>LIVE</b> ${detail}</div></article>`}
function liveTable(title,eyebrow,columns,rows,empty){return `<article class="card live-overview-table"><div class="card-title"><div><p class="section-eyebrow">${eyebrow}</p><h3>${title}</h3></div><span class="badge">${rows.length} records</span></div><div class="table-wrap"><table><thead><tr>${columns.map(c=>`<th>${c[0]}</th>`).join('')}</tr></thead><tbody>${rows.length?rows.map(row=>`<tr>${columns.map(c=>`<td>${c[1](row)}</td>`).join('')}</tr>`).join(''):`<tr><td colspan="${columns.length}"><div class="empty-state">${empty}</div></td></tr>`}</tbody></table></div></article>`}
function operationsLiveOverview(){const records=savedData().filter(r=>r.module==='operations'),purchases=records.filter(r=>r.form==='Purchase Cycle'),open=purchases.filter(r=>!['Received','Posted'].includes(r['Approval status'])),people=records.filter(r=>r.form==='HRM & Manpower'&&/Hired|Mobilized|Active/i.test(r.Status||'')),inventory=records.filter(r=>r.form==='Inventory Management'),stock=inventory.reduce((s,r)=>s+Number(r.Quantity||0)*Number(r['Unit cost (SAR)']||0),0),expenses=records.reduce((s,r)=>s+numeric(r,['Amount (SAR)','Acquisition cost (SAR)','Basic salary (SAR)']),0),latestPurchases=purchases.slice().sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt)).slice(0,8),latestPeople=people.slice().sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt)).slice(0,8);return `<div class="hero-row"><div><h1>Operations &amp; Modules</h1><p>Live execution control across procurement, manpower, inventory, assets and site spending.</p></div></div>${sectionTabs('overview')}<div class="kpi-grid">${overviewMetric('Open purchase documents',open.length,'not received or posted','â—‡')}${overviewMetric('Active workforce records',people.length,'hired, mobilized or active','â™™')}${overviewMetric('Recorded stock value',compactMoney(stock),'quantity Ã— unit cost','â–¦')}${overviewMetric('Recorded operating spend',compactMoney(expenses),'saved operational entries','â—«')}</div><div class="overview-table-grid">${liveTable('Purchase-cycle status','PROCUREMENT',[['DOCUMENT',r=>`<b>${r['Document Number']}</b>`],['STAGE',r=>r.Stage||'â€”'],['PROJECT',r=>r.Project||'â€”'],['SUPPLIER',r=>r.Supplier||'â€”'],['AMOUNT',r=>compactMoney(r['Amount (SAR)'])],['STATUS',r=>`<span class="badge">${r['Approval status']||'Draft'}</span>`]],latestPurchases,'No purchase-cycle documents have been entered.')}${liveTable('Workforce deployment','MANPOWER',[['EMPLOYEE / POSITION',r=>`<b>${r['Employee / position']||'â€”'}</b>`],['NUMBER',r=>r['Employee number']||'â€”'],['PROJECT',r=>r['Project / department']||'â€”'],['JOINING',r=>r['Joining / required date']||'â€”'],['STATUS',r=>`<span class="badge">${r.Status||'â€”'}</span>`]],latestPeople,'No active manpower records have been entered.')}</div>`}
function accountsLiveOverview(){const records=savedData().filter(r=>r.module==='accounts'),ap=records.filter(r=>r.form==='Accounts Payable'&&!/Posted|Reversed/i.test(r['Posting status']||'')),ar=records.filter(r=>r.form==='Accounts Receivable'&&!/Paid|Cancelled/i.test(r.Status||'')),cash=records.filter(r=>r.form==='Cash Receipts & Payments'),receipts=cash.filter(r=>r['Transaction type']==='Customer Receipt').reduce((s,r)=>s+Number(r['Amount (SAR)']||0),0),payments=cash.filter(r=>r['Transaction type']!=='Customer Receipt').reduce((s,r)=>s+Number(r['Amount (SAR)']||0),0),unposted=records.filter(r=>r.form==='General Ledger & Journals'&&r['Posting status']!=='Posted'),apValue=ap.reduce((s,r)=>s+Number(r['Total including VAT (SAR)']||0),0),arValue=ar.reduce((s,r)=>s+Number(r['Total including VAT (SAR)']||0),0);return `<div class="hero-row"><div><h1>Accounting Overview</h1><p>Live subledger, cash, tax and posting-control position from saved accounting transactions.</p></div></div>${sectionTabs('overview')}<div class="kpi-grid">${overviewMetric('Open accounts payable',compactMoney(apValue),`${ap.length} supplier documents`,'â—‡')}${overviewMetric('Open accounts receivable',compactMoney(arValue),`${ar.length} customer documents`,'â–§')}${overviewMetric('Net recorded cash',compactMoney(receipts-payments),'receipts less payments','â‡„')}${overviewMetric('Unposted journals',String(unposted.length),'awaiting posting','â–¤')}</div><div class="overview-table-grid">${liveTable('Open supplier invoices','PAYABLES',[['DOCUMENT',r=>`<b>${r['Document Number']}</b>`],['SUPPLIER',r=>r['Supplier legal name']||'â€”'],['INVOICE',r=>r['Supplier invoice number']||'â€”'],['DUE DATE',r=>r['Due date']||'â€”'],['TOTAL',r=>compactMoney(r['Total including VAT (SAR)'])],['STATUS',r=>`<span class="badge">${r['Posting status']||'Draft'}</span>`]],ap,'No open supplier invoices have been entered.')}${liveTable('Open customer invoices','RECEIVABLES',[['DOCUMENT',r=>`<b>${r['Document Number']}</b>`],['CUSTOMER',r=>r['Customer legal name']||'â€”'],['PROJECT',r=>r['Project / contract reference']||'â€”'],['DUE DATE',r=>r['Due date']||'â€”'],['TOTAL',r=>compactMoney(r['Total including VAT (SAR)'])],['STATUS',r=>`<span class="badge">${r.Status||'Draft'}</span>`]],ar,'No open customer invoices have been entered.')}</div>`}
function financeLiveOverview(){const records=savedData().filter(r=>r.module==='finance'),revenues=records.filter(r=>r.form==='Revenue YTD'),costs=records.filter(r=>r.form==='Project Costs'),margins=records.filter(r=>r.form==='Gross Margin'),forecasts=records.filter(r=>r.form==='Cash Forecast'),revenue=revenues.reduce((s,r)=>s+Number(r['Revenue to recognize (SAR)']||0),0),cost=costs.reduce((s,r)=>s+Number(r['Amount (SAR)']||0),0),profit=revenue-cost,forecastIn=forecasts.filter(r=>r['Cash-flow type']==='Receipt').reduce((s,r)=>s+Number(r['Expected amount (SAR)']||0)*Number(r['Probability (%)']||100)/100,0),forecastOut=forecasts.filter(r=>r['Cash-flow type']!=='Receipt').reduce((s,r)=>s+Number(r['Expected amount (SAR)']||0)*Number(r['Probability (%)']||100)/100,0);return `<div class="hero-row"><div><h1>Finance Overview</h1><p>Revenue, project cost, profitability and forward cash position from saved finance records.</p></div></div>${sectionTabs('overview')}<div class="kpi-grid">${overviewMetric('Recognized revenue',compactMoney(revenue),`${revenues.length} recognition entries`,'â†—')}${overviewMetric('Recorded project cost',compactMoney(cost),`${costs.length} cost entries`,'â†˜')}${overviewMetric('Recorded gross margin',revenue?`${(profit/revenue*100).toFixed(1)}%`:'â€”',compactMoney(profit),'â—‰')}${overviewMetric('Forecast net cash',compactMoney(forecastIn-forecastOut),'probability weighted','âŒ')}</div><div class="overview-table-grid">${liveTable('Project margin forecasts','PROFITABILITY',[['PROJECT',r=>`<b>${r.Project||'â€”'}</b>`],['DATE',r=>r['Forecast date']||'â€”'],['REVENUE',r=>compactMoney(r['Forecast revenue (SAR)'])],['COST',r=>compactMoney(r['Forecast cost (SAR)'])],['PROFIT',r=>compactMoney(r['Forecast profit (SAR)'])],['MARGIN',r=>r['Forecast margin (%)']?`${r['Forecast margin (%)']}%`:'â€”']],margins,'No gross-margin forecast has been entered.')}${liveTable('Cash-flow forecast','TREASURY',[['DATE',r=>r['Expected payment / receipt date']||r['Forecast week']||'â€”'],['PROJECT / ENTITY',r=>`<b>${r['Project / entity']||'â€”'}</b>`],['TYPE',r=>r['Cash-flow type']||'â€”'],['AMOUNT',r=>compactMoney(r['Expected amount (SAR)'])],['PROBABILITY',r=>`${r['Probability (%)']||0}%`],['OWNER',r=>r.Owner||'â€”']],forecasts,'No cash-flow forecast lines have been entered.')}</div>`}
const sectionPageLiveOverviewCore=sectionPage;
sectionPage=function(page,view='overview'){if(view==='overview'&&page==='operations')return operationsLiveOverview();if(view==='overview'&&page==='accounts')return accountsLiveOverview();if(view==='overview'&&page==='finance')return financeLiveOverview();return sectionPageLiveOverviewCore(page,view)};
function markDashboardBenchmarks(){const notice=document.querySelector('.demo-notice');if(notice)notice.innerHTML='<b>Live data:</b> Figures below are calculated only from records entered into MUSTAQEEM.'}
function enhanceRecordDrivenOverview(page,view='overview'){const records=savedData();if(page==='dashboard'){const projectRows=projectOverviewRows(),contracts=projectRows.reduce((s,p)=>s+p.contract,0),ops=records.filter(r=>r.module==='operations'),cost=ops.reduce((s,r)=>s+numeric(r,['Amount (SAR)','Acquisition cost (SAR)','Basic salary (SAR)']),0),receivable=records.filter(r=>r.form==='Accounts Receivable'&&!/Paid|Cancelled/i.test(r.Status||'')).reduce((s,r)=>s+numeric(r,['Total including VAT (SAR)','Taxable amount excluding VAT (SAR)']),0),opportunities=records.filter(r=>r.form==='Contract Opportunities').length;updateKpiCards([['Awarded contract value',contracts?compactMoney(contracts):'â€”','LIVE'],['Recorded operating cost',compactMoney(cost),'LIVE'],['Open receivables',compactMoney(receivable),'LIVE'],['Contract opportunities',String(opportunities),'LIVE']]);markDashboardBenchmarks();return}if(view==='overview'&&page==='marketing'){const data=marketingOverviewData();updateKpiCards(data.kpis);const host=document.querySelector('.pipeline-table-host');if(host)host.innerHTML=accurateOpportunityPipeline()}if(view==='overview'&&page==='projectcosting'){const rows=projectOverviewRows(),contract=rows.reduce((s,p)=>s+p.contract,0),budget=rows.reduce((s,p)=>s+p.budget,0),actual=rows.reduce((s,p)=>s+p.actual,0),margin=contract?(contract-Math.max(actual,budget))/contract*100:0;updateKpiCards([['Awarded Projects',String(rows.length),'LIVE'],['Approved Baseline',compactMoney(budget),'LIVE'],['Recorded Cost',compactMoney(actual),'LIVE'],['Budget Margin',contract?`${margin.toFixed(1)}%`:'â€”','LIVE']]);const host=document.querySelector('.portfolio-table-host');if(host)host.innerHTML=accurateProjectPortfolio();const select=document.querySelector('[data-project-filter]');if(select)select.innerHTML=`<option value="all">All projects</option>${rows.map(p=>`<option value="${p.code}">${p.code} â€” ${p.name}</option>`).join('')}`}if(view==='overview'&&page==='operations'){const ops=records.filter(r=>r.module==='operations'),purchases=ops.filter(r=>r.form==='Purchase Cycle'&&!/Received|Posted/i.test(r['Approval status']||'')).length,workers=ops.filter(r=>r.form==='HRM & Manpower'&&/Hired|Mobilized|Active/i.test(r.Status||'')).length,stock=ops.filter(r=>r.form==='Inventory Management').reduce((s,r)=>s+Number(r.Quantity||0)*Number(r['Unit cost (SAR)']||0),0),spend=ops.reduce((s,r)=>s+numeric(r,['Amount (SAR)','Acquisition cost (SAR)','Basic salary (SAR)']),0);updateKpiCards([['Open Purchases',String(purchases),'LIVE'],['Active Workforce Records',String(workers),'LIVE'],['Recorded Stock Value',compactMoney(stock),'LIVE'],['Recorded Operating Spend',compactMoney(spend),'LIVE']]);content.insertAdjacentHTML('beforeend',operationsOverviewSummary())}if(['accounts','finance'].includes(page)){document.querySelectorAll('.module-card').forEach(card=>{const key=card.dataset.formKey,rows=records.filter(r=>r.module===page&&r.form===key),value=rows.reduce((s,r)=>s+numeric(r,['Total including VAT (SAR)','Amount (SAR)','Forecast revenue (SAR)','Forecast cost (SAR)','Outstanding amount (SAR)','Expected amount (SAR)','Debit amount (SAR)']),0),footer=card.querySelector('footer b');if(footer)footer.textContent=value?`${rows.length} Â· ${compactMoney(value)}`:`${rows.length} records`});content.insertAdjacentHTML('beforeend',controlOverviewSummary(page))}}
const renderDataAccuracyCore=render;
render=function(page,view='overview'){renderDataAccuracyCore(page,view);enhanceRecordDrivenOverview(page,view)};
