function bindKsaTransactionCalculations(key){
 const byName=name=>document.querySelector(`[name="${name}"]`),num=name=>Number(byName(name)?.value||0),set=(name,value)=>{const field=byName(name);if(field)field.value=Number.isFinite(value)?value.toFixed(2):'0.00'};
 const watch=(names,callback)=>names.forEach(name=>byName(name)?.addEventListener('input',callback));
 if(['Billing & Collections','Purchase Cycle','Site & Other Expenses','Accounts Payable','Accounts Receivable','VAT & Tax Entries'].includes(key)){
  const treatment=byName('VAT treatment'),calc=()=>{const rateField=byName('VAT rate (%)');if(rateField&&treatment)rateField.value=/Standard-rated\s*15%/i.test(treatment.value)?'15.00':'0.00';const base=num('Taxable amount excluding VAT (SAR)')||num('Amount excluding VAT (SAR)'),rate=num('VAT rate (%)');set('VAT amount (SAR)',base*rate/100);set('Total including VAT (SAR)',base+base*rate/100)};
  watch(['Taxable amount excluding VAT (SAR)','Amount excluding VAT (SAR)'],calc);treatment?.addEventListener('change',calc);calc();
 }
 if(key==='Purchase Cycle'){
  const calc=()=>{const amount=Math.max(0,num('Quantity')*num('Unit price excluding VAT (SAR)')-num('Discount (SAR)'));set('Amount excluding VAT (SAR)',amount);const rate=num('VAT rate (%)');set('VAT amount (SAR)',amount*rate/100);set('Total including VAT (SAR)',amount+amount*rate/100)};
  watch(['Quantity','Unit price excluding VAT (SAR)','Discount (SAR)','VAT rate (%)'],calc);calc();
 }
 if(key==='Attendance & Payroll'){
  const calc=()=>{const gross=['Basic salary (SAR)','Housing allowance (SAR)','Transport allowance (SAR)','Other allowances (SAR)','Overtime amount (SAR)','Bonus / incentive (SAR)'].reduce((s,n)=>s+num(n),0),deductions=['Employee GOSI deduction (SAR)','Other deductions (SAR)','Loan / advance recovery (SAR)'].reduce((s,n)=>s+num(n),0);set('Gross earnings (SAR)',gross);set('Net salary (SAR)',gross-deductions)};
  watch(['Basic salary (SAR)','Housing allowance (SAR)','Transport allowance (SAR)','Other allowances (SAR)','Overtime amount (SAR)','Bonus / incentive (SAR)','Employee GOSI deduction (SAR)','Other deductions (SAR)','Loan / advance recovery (SAR)'],calc);calc();
 }
 if(key==='Inventory Management'){const calc=()=>set('Movement value (SAR)',num('Quantity')*num('Unit cost (SAR)'));watch(['Quantity','Unit cost (SAR)'],calc);calc()}
 if(key==='Fixed Assets'){const calc=()=>set('Total capitalized cost (SAR)',num('Acquisition cost excluding VAT (SAR)')+num('Non-recoverable VAT / duties (SAR)')+num('Capitalized ancillary cost (SAR)'));watch(['Acquisition cost excluding VAT (SAR)','Non-recoverable VAT / duties (SAR)','Capitalized ancillary cost (SAR)'],calc);calc()}
}
configurePurchaseChain=function(){const stage=document.querySelector('[name="Stage"]'),records=operationalRecords('Purchase Cycle'),order=['Purchase Requisition','Request for Quotation','Bid Comparison','Purchase Order','Goods Receipt','Service Entry Sheet','Supplier Invoice','Payment Request'],source=insertOperationalSource('Source purchase document','Previous purchase-cycle document',[],r=>r['Document Number']);if(!stage||!source)return;const refresh=()=>{const index=order.indexOf(stage.value),required=index>0?order[index-1]:null,used=new Set(records.filter(r=>r.Stage===stage.value).map(r=>r['Source purchase document'])),eligible=required?records.filter(r=>r.Stage===required&&!used.has(r['Document Number'])):[];source.closest('label').hidden=!required;source.required=Boolean(required);source.innerHTML=`<option value="">${eligible.length?'Select previous-stage documentâ€¦':required?`No unused ${required} document available`:'Not required for requisition'}</option>${eligible.map(r=>`<option value="${r['Document Number']}">${r['Document Number']} â€” ${r['Item / service']||r.Supplier||required}</option>`).join('')}`};stage.addEventListener('change',refresh);source.addEventListener('change',()=>{const record=records.find(r=>r['Document Number']===source.value);if(!record)return;['Project','Supplier','Item / service','Unit of measure','Quantity','Unit price excluding VAT (SAR)','Discount (SAR)','Amount excluding VAT (SAR)','VAT treatment','Payment terms','Delivery location / warehouse'].forEach(name=>setFormValue(name,record[name]));['Quantity','Unit price excluding VAT (SAR)','Discount (SAR)','VAT treatment'].forEach(name=>document.querySelector(`[name="${name}"]`)?.dispatchEvent(new Event(name==='VAT treatment'?'change':'input',{bubbles:true})))});refresh()};
const openFormKsaFieldsCore=openForm;
openForm=function(page=currentPage,key=''){openFormKsaFieldsCore(page,key);if(['operations','accounts'].includes(page))bindKsaTransactionCalculations(key)};
