function externalPortalsPage(){const portals=[{code:'E',type:'EMPLOYEE',title:'Self-service & Mobile',description:'Payslips, leave, attendance, personal documents, assigned projects and employee requests.',features:['Mobile-first employee experience','Approval and payroll notifications','Document-expiry alerts']},{code:'S',type:'SUBCONTRACTOR',title:'Progress & Certification',description:'Contract, BOQ, progress claims, site measurements, retention, certificates and payment status.',features:['Digital progress-claim submission','Measurement and certification workflow','Compliance-document tracking']},{code:'C',type:'CLIENT',title:'Progress & Billing',description:'Approved project progress, milestones, photographs, invoices, certificates and account statements.',features:['Controlled read-only project view','Invoice and receipt history','Secure document sharing']},{code:'V',type:'SUPPLIER',title:'Sourcing & Invoicing',description:'RFQs, quotations, purchase orders, delivery appointments, invoices, GRNs and payment status.',features:['Quotation submission','Purchase-order acknowledgement','GRN and payment visibility']}];return `<div class="hero-row"><div><p class="section-eyebrow">SECURE COLLABORATION</p><h1>Purpose-built External Portals</h1><p>Each external party will see only the transactions, documents and actions relevant to them.</p></div></div><div class="portal-notice"><b>Portal preview:</b> These cards show the planned external applications. Secure login and external access require the production backend.</div><div class="portal-grid">${portals.map(portal=>`<article class="card portal-card"><div class="portal-code">${portal.code}</div><div><p class="section-eyebrow">${portal.type}</p><h3>${portal.title}</h3><p>${portal.description}</p><ul>${portal.features.map(feature=>`<li>${feature}</li>`).join('')}</ul></div></article>`).join('')}</div>`}
const renderExternalPortalsCore=render;
render=function(page,view='overview'){if(page!=='externalportals'){renderExternalPortalsCore(page,view);return}currentPage=page;document.querySelectorAll('.nav-item').forEach(button=>button.classList.toggle('active',button.dataset.page===page));document.getElementById('crumb').textContent=titles[page][0];document.getElementById('pageTitle').textContent=titles[page][1];content.innerHTML=externalPortalsPage();document.querySelector('.sidebar').classList.remove('open');window.scrollTo(0,0)};
