function pendingBidDecisions(){return savedWorkflowRecords().filter(r=>r.form==='Bid / No-Bid Decision'&&(!r.Decision||r.Decision==='Pending Review'))}
function decideBid(documentNumber,decision){
 if(currentRole!=='Director'){toast('Only Director can approve the Bid / No-Bid decision');return}
 const records=savedWorkflowRecords(),record=records.find(r=>r.form==='Bid / No-Bid Decision'&&r['Document Number']===documentNumber);
 if(!record)return;
 record.Decision=decision;
 record['Decision authority']='Director';
 record['Decision date']=new Date().toISOString().slice(0,10);
 record['Approved by']='Director';
 record['Decision remarks']=decision==='Approved to Bid'?'Approved to prepare and submit the bidding proposal.':decision==='Returned for Revision'?'Returned to the estimation and bidding team for revision.':'Management approved the No-Bid recommendation.';
 localStorage.setItem('mustaqeem-demo-records',JSON.stringify(records));
 render('approvals');toast(`${documentNumber} marked ${decision}`);
}
