function ledgerLines(){return recordsFor('General Ledger & Journals')}
function postedLedger(){return ledgerLines().filter(r=>r['Posting status']==='Posted')}
function journalBatch(record){return record['Journal batch reference']||record['Source document reference']||record['Document Number']}
function journalBatchPosition(batch,include){const rows=[...ledgerLines().filter(r=>journalBatch(r)===batch&&r['Posting status']!=='Reversed'),...(include?[include]:[])],debit=rows.reduce((s,r)=>s+Number(r['Debit amount (SAR)']||0),0),credit=rows.reduce((s,r)=>s+Number(r['Credit amount (SAR)']||0),0);return {rows,debit,credit,difference:debit-credit,balanced:rows.length>1&&Math.abs(debit-credit)<.01}}
function unbalancedJournalBatches(){const batches=[...new Set(ledgerLines().filter(r=>r['Posting status']!=='Reversed').map(journalBatch))];return batches.filter(batch=>{const p=journalBatchPosition(batch);return (p.rows.some(r=>r['Posting status']==='Posted')||p.rows.some(r=>r['Posting status']==='Approved'))&&!p.balanced})}
function closedPeriods(){return recordsFor('Month-End Close').filter(r=>r['Close status']==='Closed').map(r=>r['Accounting period'])}
function recordPeriod(data){const candidates=['Posting period','Accounting period','Payroll period','Recognition period','Journal date','Invoice issue date','Transaction date','Value date','Statement date','Request / document date','Movement date','Acquisition date','Forecast date','Tax period to'];for(const name of candidates){const value=String(data[name]||'');const match=value.match(/^\d{4}-\d{2}/);if(match)return match[0]}return ''}
function configureJournalBatch(){const batch=document.querySelector('[name="Journal batch reference"]'),debit=document.querySelector('[name="Debit amount (SAR)"]'),credit=document.querySelector('[name="Credit amount (SAR)"]'),status=document.querySelector('[name="Posting status"]');const validate=()=>{const d=Number(debit?.value||0),c=Number(credit?.value||0),invalid=(d>0&&c>0)||(d===0&&c===0);debit?.setCustomValidity(invalid?'Enter either a debit or a credit amount on each journal line.':'');credit?.setCustomValidity(invalid?'Enter either a debit or a credit amount on each journal line.':'');if(status?.value==='Posted'&&batch?.value){const current={'Debit amount (SAR)':d,'Credit amount (SAR)':c,'Posting status':'Posted'},position=journalBatchPosition(batch.value,current);status.setCustomValidity(position.balanced?'':`Batch is not balanced. Difference: ${compactMoney(Math.abs(position.difference))}`)}else status?.setCustomValidity('')};[batch,debit,credit,status].forEach(f=>{f?.addEventListener('input',validate);f?.addEventListener('change',validate)});validate()}
function closeChecklist(period){const inPeriod=r=>recordPeriod(r)===period,unposted=ledgerLines().filter(r=>inPeriod(r)&&!['Posted','Reversed'].includes(r['Posting status']||'')).length,bank=recordsFor('Bank & Reconciliation').filter(r=>inPeriod(r)&&!['Matched','Reconciled'].includes(r['Reconciliation status']||'')).length,ar=recordsFor('Accounts Receivable').filter(r=>inPeriod(r)&&!['Posted','Part Paid','Paid','Cancelled'].includes(r.Status||'')).length,ap=recordsFor('Accounts Payable').filter(r=>inPeriod(r)&&!['Posted','Part Paid','Paid','Reversed'].includes(r['Posting status']||'')).length,vat=recordsFor('VAT & Tax Entries').filter(r=>inPeriod(r)&&!['Reviewed','Included in Return','Filed','Paid / Refunded','Adjusted'].includes(r.Status||'')).length,payroll=recordsFor('Attendance & Payroll').filter(r=>inPeriod(r)&&!['Approved','Paid','Reversed'].includes(r['Payroll status']||'')).length,inventory=recordsFor('Inventory Management').filter(r=>inPeriod(r)&&!r['Approved by']).length,assets=recordsFor('Fixed Assets').filter(r=>inPeriod(r)&&!['Active','Disposed'].includes(r.Status||'')).length,unbalanced=unbalancedJournalBatches().length;return {unbalanced,unposted,bank,ar,ap,vat,payroll,inventory,assets,blocking:unbalanced+unposted+bank+vat+payroll+inventory+assets}}
function configureMonthClose(){const period=document.querySelector('[name="Accounting period"]'),status=document.querySelector('[name="Close status"]');const refresh=()=>{const c=closeChecklist(period?.value||'');setFormValue('Unbalanced journal batches',c.unbalanced);setFormValue('Unposted journal lines',c.unposted);setFormValue('Unreconciled bank entries',c.bank);setFormValue('Unposted customer invoices',c.ar);setFormValue('Unposted supplier invoices',c.ap);setFormValue('VAT entries pending review',c.vat);setFormValue('Payroll pending posting',c.payroll);setFormValue('Inventory movements pending posting',c.inventory);setFormValue('Fixed assets pending capitalization',c.assets);setFormValue('Close checklist result',c.blocking?'Period cannot close until blocking exceptions are cleared. Open AR/AP remain visible for ageing and do not block close.':'All blocking controls passed. Period is ready to close.');status?.setCustomValidity(status.value==='Closed'&&c.blocking?'Clear all blocking month-end exceptions before closing the period.':'')};period?.addEventListener('change',refresh);status?.addEventListener('change',refresh);refresh()}
function pushAutoLine(records,batch,source,account,debit,credit,project,narration){addJournalLine(records,batch,source,account,debit,credit,project,narration);const line=records.at(-1);line['Journal batch reference']=batch;line['Posting period']=new Date().toISOString().slice(0,7)}
function autoPostCustomerInvoice(data){setTimeout(()=>{if(data.Status!=='Posted')return;const records=savedData(),batch=data['Document Number'];if(records.some(r=>r.form==='General Ledger & Journals'&&r['Source document reference']===batch))return;const base=Number(data['Taxable amount excluding VAT (SAR)']||0),vat=Number(data['VAT amount (SAR)']||0),gross=Number(data['Total including VAT (SAR)']||base+vat),retention=Number(data['Retention deduction (SAR)']||0),advance=Number(data['Advance recovery (SAR)']||0),project=data['Project / contract reference'];pushAutoLine(records,batch,'Accounts Receivable','112100 - Accounts Receivable - Contracting',gross,0,project,'Customer invoice receivable');pushAutoLine(records,batch,'Accounts Receivable',data['Revenue account'],0,base,project,'Contract revenue');if(vat)pushAutoLine(records,batch,'Accounts Receivable','212100 - Output VAT Payable',0,vat,project,'Output VAT');if(retention){pushAutoLine(records,batch,'Accounts Receivable','112200 - Retention Receivable',retention,0,project,'Customer retention receivable');pushAutoLine(records,batch,'Accounts Receivable','112100 - Accounts Receivable - Contracting',0,retention,project,'Reclassify retention')}if(advance){pushAutoLine(records,batch,'Accounts Receivable','214100 - Customer Advances / Contract Liability',advance,0,project,'Recover customer advance');pushAutoLine(records,batch,'Accounts Receivable','112100 - Accounts Receivable - Contracting',0,advance,project,'Apply customer advance')}localStorage.setItem('mustaqeem-demo-records',JSON.stringify(records))},0)}
function autoPostCustomerReceipt(data){setTimeout(()=>{if(data.Status!=='Posted'||data['Transaction type']!=='Customer Receipt')return;const records=savedData(),batch=data['Document Number'];if(records.some(r=>r.form==='General Ledger & Journals'&&r['Source document reference']===batch))return;const amount=Number(data['Allocation / settlement amount (SAR)']||data['Amount (SAR)']||0),project=data['Project / cost centre'];pushAutoLine(records,batch,'Cash & Bank','111200 - Bank - SAR Operating',amount,0,project,'Customer receipt');pushAutoLine(records,batch,'Cash & Bank','112100 - Accounts Receivable - Contracting',0,amount,project,'Settle customer receivable');localStorage.setItem('mustaqeem-demo-records',JSON.stringify(records))},0)}
function autoPostPayroll(data){setTimeout(()=>{if(!['Approved','Paid'].includes(data['Payroll status']))return;const records=savedData(),batch=data['Document Number'];if(records.some(r=>r.form==='General Ledger & Journals'&&r['Source document reference']===batch))return;const gross=Number(data['Gross earnings (SAR)']||0),employer=Number(data['Employer GOSI contribution (SAR)']||0),employee=Number(data['Employee GOSI deduction (SAR)']||0),other=Number(data['Other deductions (SAR)']||0)+Number(data['Loan / advance recovery (SAR)']||0),net=Number(data['Net salary (SAR)']||0),project=data.Project;pushAutoLine(records,batch,'Payroll','512100 - Direct Labour - Basic Salaries',gross,0,project,'Gross payroll cost');if(employer)pushAutoLine(records,batch,'Payroll','512130 - Direct Labour - GOSI',employer,0,project,'Employer GOSI cost');pushAutoLine(records,batch,'Payroll','213100 - Payroll Payable',0,net,project,'Net payroll payable');if(employee+employer)pushAutoLine(records,batch,'Payroll','213110 - GOSI Payable',0,employee+employer,project,'GOSI payable');if(other)pushAutoLine(records,batch,'Payroll','214100 - Customer Advances / Contract Liability',0,other,project,'Payroll deductions / advances');localStorage.setItem('mustaqeem-demo-records',JSON.stringify(records))},0)}
function autoPostInventory(data){setTimeout(()=>{if(data.Movement!=='Material Issue'||!data['Approved by'])return;const records=savedData(),batch=data['Document Number'];if(records.some(r=>r.form==='General Ledger & Journals'&&r['Source document reference']===batch))return;const amount=Number(data['Movement value (SAR)']||0),project=data.Project;pushAutoLine(records,batch,'Inventory','511100 - Direct Construction Materials',amount,0,project,'Material issued to project');pushAutoLine(records,batch,'Inventory','113100 - Construction Materials Inventory',0,amount,project,'Reduce material inventory');localStorage.setItem('mustaqeem-demo-records',JSON.stringify(records))},0)}
function autoPostFixedAsset(data){setTimeout(()=>{if(data.Status!=='Active')return;const records=savedData(),batch=data['Document Number'];if(records.some(r=>r.form==='General Ledger & Journals'&&r['Source document reference']===batch))return;const amount=Number(data['Total capitalized cost (SAR)']||0),project=data['Project / location'];pushAutoLine(records,batch,'Fixed Assets',data['Asset account'],amount,0,project,'Capitalize fixed asset');pushAutoLine(records,batch,'Fixed Assets','811130 - Suspense Account',0,amount,project,'Asset acquisition clearing');localStorage.setItem('mustaqeem-demo-records',JSON.stringify(records))},0)}
const openFormCloseCore=openForm;
openForm=function(page=currentPage,key=''){openFormCloseCore(page,key);if(key==='General Ledger & Journals')configureJournalBatch();if(key==='Month-End Close')configureMonthClose()};
document.addEventListener('submit',e=>{if(e.target.id!=='entryForm')return;const key=e.target.dataset.formKey,data=Object.fromEntries(new FormData(e.target)),period=recordPeriod(data);if(key!=='Month-End Close'&&period&&closedPeriods().includes(period)){e.preventDefault();e.stopImmediatePropagation();toast(`Accounting period ${period} is closed`);return}if(key==='Month-End Close'&&data['Close status']==='Closed'){const c=closeChecklist(data['Accounting period']);if(currentRole!=='Director'){e.preventDefault();e.stopImmediatePropagation();toast('Only Director can close an accounting period');return}if(c.blocking){e.preventDefault();e.stopImmediatePropagation();toast('Month-end close blocked by unresolved accounting controls');return}}if(key==='General Ledger & Journals'&&data['Posting status']==='Posted'){const p=journalBatchPosition(data['Journal batch reference'],data);if(!p.balanced){e.preventDefault();e.stopImmediatePropagation();toast(`Journal batch is not balanced by ${compactMoney(Math.abs(p.difference))}`);return}setTimeout(()=>{const records=savedData();records.forEach(r=>{if(r.form==='General Ledger & Journals'&&journalBatch(r)===data['Journal batch reference']&&r['Posting status']!=='Reversed')r['Posting status']='Posted'});localStorage.setItem('mustaqeem-demo-records',JSON.stringify(records))},0)}if(e.defaultPrevented)return;if(key==='Accounts Receivable')autoPostCustomerInvoice(data);if(key==='Cash Receipts & Payments')autoPostCustomerReceipt(data);if(key==='Attendance & Payroll')autoPostPayroll(data);if(key==='Inventory Management')autoPostInventory(data);if(key==='Fixed Assets')autoPostFixedAsset(data)},true);
