function ledgerAccountSummary(){const map={};postedLedger().forEach(r=>{const code=r['Account code']||'Unassigned',entry=map[code]||(map[code]={account:code,debit:0,credit:0});entry.debit+=Number(r['Debit amount (SAR)']||0);entry.credit+=Number(r['Credit amount (SAR)']||0)});return Object.values(map).map(r=>({...r,balance:r.debit-r.credit}))}
function financialReportHtml(name){const summary=ledgerAccountSummary(),money=n=>`SAR ${Number(n||0).toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}`,table=(columns,rows)=>`<div class="table-wrap"><table><thead><tr>${columns.map(c=>`<th>${c}</th>`).join('')}</tr></thead><tbody>${rows.length?rows.join(''):`<tr><td colspan="${columns.length}"><div class="empty-state">No posted ledger transactions are available.</div></td></tr>`}</tbody></table></div>`;let body='';if(name==='Trial Balance')body=table(['ACCOUNT','DEBIT','CREDIT','BALANCE'],summary.map(r=>`<tr><td><b>${r.account}</b></td><td>${money(r.debit)}</td><td>${money(r.credit)}</td><td>${money(r.balance)}</td></tr>`));if(name==='Profit and Loss'){const rows=summary.filter(r=>/^[456]/.test(r.account)),revenue=rows.filter(r=>/^4/.test(r.account)).reduce((s,r)=>s-r.balance,0),expense=rows.filter(r=>/^[56]/.test(r.account)).reduce((s,r)=>s+r.balance,0);body=table(['ACCOUNT','TYPE','AMOUNT'],[...rows.map(r=>`<tr><td>${r.account}</td><td>${/^4/.test(r.account)?'Revenue':'Expense'}</td><td>${money(/^4/.test(r.account)?-r.balance:r.balance)}</td></tr>`),`<tr><td><b>NET PROFIT / (LOSS)</b></td><td></td><td><b>${money(revenue-expense)}</b></td></tr>`])}if(name==='Balance Sheet'){const rows=summary.filter(r=>/^[123]/.test(r.account));body=table(['ACCOUNT','SECTION','BALANCE'],rows.map(r=>`<tr><td>${r.account}</td><td>${/^1/.test(r.account)?'Asset':/^2/.test(r.account)?'Liability':'Equity'}</td><td>${money(/^1/.test(r.account)?r.balance:-r.balance)}</td></tr>`))}if(name==='Cash Flow Statement'){const rows=allPostedBankTransactions(),receipts=rows.filter(r=>r['Transaction type']==='Customer Receipt').reduce((s,r)=>s+Number(r['Amount (SAR)']||0),0),payments=rows.filter(r=>r['Transaction type']==='Supplier Payment').reduce((s,r)=>s+Number(r['Amount (SAR)']||0),0);body=table(['CASH FLOW','AMOUNT'],[`<tr><td>Customer receipts</td><td>${money(receipts)}</td></tr>`,`<tr><td>Supplier payments</td><td>${money(-payments)}</td></tr>`,`<tr><td><b>NET OPERATING CASH FLOW</b></td><td><b>${money(receipts-payments)}</b></td></tr>`])}return `<article class="card report-preview"><div class="card-title"><div><p class="section-eyebrow">POSTED ACCOUNTING RECORDS</p><h3>${name}</h3></div><button class="action-btn" data-print-report>Print</button></div>${body}</article>`}
const renderSectionReportFinancialCore=renderSectionReport;
renderSectionReport=function(page,index){const definition=sectionReportDefinitions[page]?.[Number(index)];if(definition&&['Trial Balance','Profit and Loss','Balance Sheet','Cash Flow Statement'].includes(definition[0])){const preview=document.getElementById('sectionReportPreview');preview.innerHTML=financialReportHtml(definition[0]);preview.scrollIntoView({behavior:'smooth',block:'start'});return}renderSectionReportFinancialCore(page,index)};
