const originalLanguageText=new WeakMap();
function translateTextNodes(root,lang){if(!root)return;const walker=document.createTreeWalker(root,NodeFilter.SHOW_TEXT);let node;while(node=walker.nextNode()){const original=originalLanguageText.get(node)??node.nodeValue;originalLanguageText.set(node,original);if(!original.trim())continue;const leading=original.match(/^\s*/)?.[0]||'',trailing=original.match(/\s*$/)?.[0]||'',key=original.trim();node.nodeValue=leading+(lang==='ar'?(arabicUi[key]||key):key)+trailing}}
function applyInterfaceLanguage(lang=languageSwitcher.value){const arabic=lang==='ar';document.documentElement.lang=lang;document.documentElement.dir=arabic?'rtl':'ltr';document.body.classList.toggle('lang-ar',arabic);[document.querySelector('.sidebar'),document.querySelector('.topbar'),document.querySelector('.breadcrumb-bar'),document.getElementById('content'),document.getElementById('quickPanel'),document.getElementById('formModal')].forEach(root=>translateTextNodes(root,lang));localStorage.setItem('mustaqeem-language',lang)}
languageSwitcher.value=localStorage.getItem('mustaqeem-language')||'en';
languageSwitcher.addEventListener('change',()=>applyInterfaceLanguage(languageSwitcher.value));
[document.querySelector('.breadcrumb-bar'),document.getElementById('content'),document.getElementById('quickPanel'),document.getElementById('formModal')].forEach(root=>new MutationObserver(()=>applyInterfaceLanguage(languageSwitcher.value)).observe(root,{childList:true,subtree:true}));
applyInterfaceLanguage(languageSwitcher.value);

