titles.validation=['Control / Demo Validation','Demo Validation Centre'];
function validationHas(form,test=()=>true){return savedData().some(r=>r.form===form&&test(r))}
function validationStages(){const definitions=[
 ['Contract Opportunity','marketing','Contract Opportunities',validationHas('Contract Opportunities'),true,'Enter the contract opportunity.'],
 ['Director Qualification','marketing','Qualification Review',validationHas('Contract Opportunities',r=>r['Qualification decision']==='Qualified'),validationHas('Contract Opportunities'),'Director must qualify the opportunity.'],
 ['Cost Estimate','marketing','Cost Estimation & Scenarios',validationHas('Cost Estimation & Scenarios'),validationHas('Contract Opportunities',r=>r['Qualification decision']==='Qualified'),'Create the tender cost estimate.'],
 ['Bid / No-Bid Approval','marketing','Bid / No-Bid Decision',validationHas('Bid / No-Bid Decision',r=>r.Decision==='Approved to Bid'),validationHas('Cost Estimation & Scenarios'),'Director must approve the bid decision.'],
 ['Proposal & Award','marketing','Proposal & Submission',validationHas('Award / Loss Register',r=>r.Outcome==='Awarded'),validationHas('Bid / No-Bid Decision',r=>r.Decision==='Approved to Bid'),'Submit the proposal and record the award.'],
 ['Project & Baseline','projectcosting','Baseline Budgets',validationHas('Baseline Budgets'),validationHas('Awarded Projects'),'Mobilize the awarded project and approve its baseline.'],
 ['Authorized Operations','projectcosting','Project Operations',validationHas('Project Operations',r=>['Authorized','Executing','Completed'].includes(r['Operations status'])),validationHas('Baseline Budgets'),'Authorize project operations.'],
 ['Purchase / Manpower Cost','operations','Purchase Cycle',validationHas('Purchase Cycle')||validationHas('Attendance & Payroll'),validationHas('Project Operations',r=>['Authorized','Executing','Completed'].includes(r['Operations status'])),'Record controlled purchase or manpower transactions.'],
 ['Certification & Revenue','projectcosting','Billing & Certification',validationHas('Revenue & CRM Cycle',r=>r.Status==='Recognized'),validationHas('Billing & Certification',r=>r['Certification status']==='Certified'),'Certify work and recognize revenue.'],
 ['Customer Invoice','accounts','Accounts Receivable',validationHas('Accounts Receivable',r=>/Posted|Part Paid|Paid|Overdue/.test(r.Status||'')),validationHas('Revenue & CRM Cycle',r=>r.Status==='Recognized'),'Post the customer tax invoice.'],
 ['Customer Receipt','accounts','Cash Receipts & Payments',validationHas('Cash Receipts & Payments',r=>r['Transaction type']==='Customer Receipt'&&/Posted|Cleared/.test(r.Status||'')),validationHas('Accounts Receivable',r=>/Posted|Part Paid|Paid|Overdue/.test(r.Status||'')),'Post and allocate the customer receipt.'],
 ['Supplier Payment','accounts','Cash Receipts & Payments',validationHas('Cash Receipts & Payments',r=>r['Transaction type']==='Supplier Payment'&&/Posted|Cleared/.test(r.Status||'')),validationHas('Accounts Payable',r=>/Posted|Part Paid|Paid/.test(r['Posting status']||'')),'Approve and post the supplier payment.'],
 ['Bank Reconciliation','accounts','Bank & Reconciliation',validationHas('Bank & Reconciliation',r=>['Matched','Reconciled'].includes(r['Reconciliation status'])),validationHas('Cash Receipts & Payments',r=>/Posted|Cleared/.test(r.Status||'')),'Match posted bank transactions.'],
 ['Ledger & Month Close','finance','Month-End Close',validationHas('Month-End Close',r=>r['Close status']==='Closed'),validationHas('General Ledger & Journals',r=>r['Posting status']==='Posted'),'Review balanced journals and close the period.']
 ];let chainOpen=true;return definitions.map((s,index)=>{const [name,page,form,complete,ready,help]=s,status=complete?'Completed':chainOpen&&ready?'Ready':chainOpen?'Not started':'Blocked';if(!complete)chainOpen=false;return {index:index+1,name,page,form,status,help}})}
function projectTrace(project){if(project==='all')return [];const records=savedData(),award=awardedProjectRecords().find(r=>r['Document Number']===project),trace=award?workflowTraceForProject(project):{},find=(form,predicate)=>records.find(r=>r.form===form&&predicate(r)),items=[['Opportunity',trace.opportunity],['Estimate',trace.estimate],['Bid decision',trace.decision],['Proposal',trace.proposal],['Award',trace.award],['Project',award],['Baseline',find('Baseline Budgets',r=>r.Project===project)],['Operations',find('Project Operations',r=>r.Project===project)],['Certificate',find('Billing & Certification',r=>r.Project===project)],['Revenue',find('Revenue & CRM Cycle',r=>r.Project===project)],['Customer invoice',find('Accounts Receivable',r=>r['Project / contract reference']===project)]];return items.map(([stage,r])=>({stage,document:r?.['Document Number']||'â€”',status:r?'Saved':'Missing'}))}
function demoValidationPage(project=localStorage.getItem('mustaqeem-validation-project')||'all'){const stages=validationStages(),audit=window.mustaqeemDemoAudit(),projects=awardedProjectRecords(),trace=projectTrace(project),completed=stages.filter(s=>s.status==='Completed').length;return `<div class="validation-hero"><div><p class="section-eyebrow">END-TO-END CONTROL TEST</p><h1>Demo Validation Centre</h1><p>Follow the transaction chain, identify missing prerequisites and verify accounting integrity.</p></div><div class="validation-actions"><button data-validation-export>Export validation</button><button class="danger-action" data-validation-reset>Reset transaction data</button></div></div><div class="validation-toolbar"><label>Project document trace<select id="validationProject"><option value="all">All projects / overall workflow</option>${projects.map(p=>`<option value="${p['Document Number']}"${p['Document Number']===project?' selected':''}>${p['Project code']||p['Document Number']} â€” ${p['Project name']}</option>`).join('')}</select></label></div><div class="register-kpis validation-kpis"><article class="card"><span>Workflow completion</span><h3>${completed} / ${stages.length}</h3></article><article class="card"><span>Ready next steps</span><h3>${stages.filter(s=>s.status==='Ready').length}</h3></article><article class="card"><span>Blocked stages</span><h3>${stages.filter(s=>s.status==='Blocked').length}</h3></article><article class="card"><span>Audit result</span><h3 class="${audit.passed?'validation-pass':'validation-fail'}">${audit.passed?'Passed':`${audit.issues.length} exceptions`}</h3></article></div><article class="card validation-flow"><div class="card-title"><div><p class="section-eyebrow">GUIDED PROCESS</p><h3>Transaction readiness</h3></div></div><div class="validation-stage-list">${stages.map(s=>`<div class="validation-stage ${s.status.toLowerCase().replace(' ','-')}"><span>${s.index}</span><div><b>${s.name}</b><small>${s.help}</small></div><em>${s.status}</em><button data-validation-target="${s.page}|${s.form}">${s.status==='Completed'?'Review':'Open form'} â†’</button></div>`).join('')}</div></article>${trace.length?`<article class="card validation-trace"><div class="card-title"><div><p class="section-eyebrow">PROJECT DOCUMENT TRACE</p><h3>Linked documents</h3></div><span class="badge">${trace.filter(x=>x.document!=='â€”').length} linked</span></div><div class="table-wrap"><table><thead><tr><th>STAGE</th><th>DOCUMENT</th><th>STATUS</th></tr></thead><tbody>${trace.map(r=>`<tr><td>${r.stage}</td><td><b>${r.document}</b></td><td>${r.status}</td></tr>`).join('')}</tbody></table></div></article>`:''}<article class="card validation-audit"><div class="card-title"><div><p class="section-eyebrow">AUTOMATED AUDIT</p><h3>Integrity checks</h3></div><span class="badge ${audit.passed?'':'amber'}">${audit.passed?'All checks passed':`${audit.issues.length} exceptions`}</span></div>${audit.passed?'<div class="empty-state validation-success">No workflow, budget, duplicate, allocation or journal-balance exceptions were detected.</div>':`<ul>${audit.issues.map(issue=>`<li>${issue}</li>`).join('')}</ul>`}</article>`}
const renderValidationCore=render;
render=function(page,view='overview'){if(page!=='validation')return renderValidationCore(page,view);currentPage='validation';document.querySelectorAll('.nav-item').forEach(b=>b.classList.toggle('active',b.dataset.page==='validation'));document.getElementById('crumb').textContent=titles.validation[0];document.getElementById('pageTitle').textContent=titles.validation[1];content.innerHTML=demoValidationPage();document.querySelector('.sidebar').classList.remove('open');window.scrollTo(0,0)};
function openValidationTarget(target){const [page,form]=target.split('|');if(page==='marketing')return renderMarketingRegister(form);if(page==='projectcosting')return renderProjectRegister(form);if(['operations','accounts','finance'].includes(page))return renderModuleRegister(page,form);render(page,'forms')}
function exportValidation(){const stages=validationStages(),audit=window.mustaqeemDemoAudit(),lines=['MUSTAQEEM Demo Validation Report',`Generated: ${new Date().toLocaleString()}`,'',...stages.map(s=>`${s.index}. ${s.name}: ${s.status} â€” ${s.help}`),'',`Audit: ${audit.passed?'PASSED':'FAILED'}`,...audit.issues.map(x=>`- ${x}`)],blob=new Blob([lines.join('\n')],{type:'text/plain'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`MUSTAQEEM-validation-${new Date().toISOString().slice(0,10)}.txt`;a.click();URL.revokeObjectURL(url)}
