detailedForms['Bank & Reconciliation']={title:'Record and reconcile bank statement line',fields:[['Company / entity','setup-select','Company Setup|Legal name (English)'],['Bank account / IBAN','setup-select','Bank Accounts|IBAN'],['Account currency','select','SAR|USD|EUR|GBP|AED'],['Accounting period','month'],['Statement number','text'],['Statement period start','date'],['Statement period end','date'],['Statement opening balance (SAR)','number'],['Statement closing balance (SAR)','number'],['Statement line reference','text'],['Bank booking date','date'],['Value date','date'],['Transaction type','select','Deposit|Withdrawal|Bank Charge|Interest Income|Interest Expense|Direct Debit|Transfer In|Transfer Out|POS Settlement|Returned Item|Other'],['Bank debit (SAR)','number'],['Bank credit (SAR)','number'],['Statement amount (SAR)','readonly'],['Book document reference','readonly'],['Book amount (SAR)','readonly'],['Match type','select','Unmatched|Exact Match|One Bank Line to Multiple Books|Multiple Bank Lines to One Book|Manual Match'],['Difference amount (SAR)','readonly'],['Difference reason','select','None|Timing Difference|Outstanding Deposit|Unpresented Payment|Bank Charge Not Booked|Interest Not Booked|Direct Debit Not Booked|Returned Item|Duplicate|Exchange Difference|Data Error|Other'],['Outstanding item classification','select','None|Deposit in Transit|Unpresented Cheque / Payment|Unrecorded Bank Debit|Unrecorded Bank Credit|Investigation Required'],['Adjustment journal reference','text'],['Reconciliation status','select','Unmatched|Partially Matched|Matched|Prepared for Review|Reconciled|Exception'],['Prepared / reconciled by','text'],['Preparation date','date'],['Reviewed by','text'],['Review status','select','Not Reviewed|Returned|Approved'],['Review date','date'],['Bank statement attachment reference','text'],['Remarks / resolution action','textarea']]};
function bankNumber(name){return Number(document.querySelector(`[name="${name}"]`)?.value||0)}
function configureCompleteBankReconciliation(){const source=document.querySelector('[name="Source bank transaction"]');if(source){source.required=false;source.closest('label')?.querySelector('.field-help')?.replaceChildren(document.createTextNode('Optional for unmatched statement lines; select a posted receipt or payment when matching.'))}const debit=document.querySelector('[name="Bank debit (SAR)"]'),credit=document.querySelector('[name="Bank credit (SAR)"]'),status=document.querySelector('[name="Reconciliation status"]'),review=document.querySelector('[name="Review status"]'),prepared=document.querySelector('[name="Prepared / reconciled by"]'),reviewed=document.querySelector('[name="Reviewed by"]');const calculate=()=>{const bankDebit=bankNumber('Bank debit (SAR)'),bankCredit=bankNumber('Bank credit (SAR)'),statement=Math.abs(bankCredit-bankDebit),book=bankNumber('Book amount (SAR)'),difference=Math.abs(statement-book);setFormValue('Statement amount (SAR)',statement||'0.00');setFormValue('Difference amount (SAR)',difference.toFixed(2));if(bankDebit&&bankCredit){debit.setCustomValidity('Enter either a bank debit or bank credit, not both.');credit.setCustomValidity('Enter either a bank debit or bank credit, not both.')}else{debit.setCustomValidity('');credit.setCustomValidity('')}const controlled=['Matched','Prepared for Review','Reconciled'].includes(status?.value),hasSource=Boolean(source?.value);status?.setCustomValidity(controlled&&(!hasSource||difference>.01)?'A matched or reconciled line requires a source book transaction and zero difference.':'');review?.setCustomValidity(review?.value==='Approved'&&prepared?.value&&reviewed?.value&&prepared.value.trim().toLowerCase()===reviewed.value.trim().toLowerCase()?'The preparer and reviewer must be different people.':'')};[debit,credit,status,review,prepared,reviewed,source].forEach(x=>x?.addEventListener('input',calculate));source?.addEventListener('change',()=>setTimeout(()=>{const type=document.querySelector('[name="Transaction type"]')?.value;if(type==='Deposit'||type==='Transfer In'||type==='Interest Income')setFormValue('Bank credit (SAR)',bankNumber('Book amount (SAR)'));else setFormValue('Bank debit (SAR)',bankNumber('Book amount (SAR)'));calculate()},0));calculate()}
const openFormBankV92=openForm;
openForm=function(page=currentPage,key=''){openFormBankV92(page,key);if(key==='Bank & Reconciliation')configureCompleteBankReconciliation()};
function bankReconciliationControl(){const rows=recordsFor('Bank & Reconciliation'),reconciled=rows.filter(r=>r['Reconciliation status']==='Reconciled'),matched=rows.filter(r=>['Matched','Prepared for Review'].includes(r['Reconciliation status'])),exceptions=rows.filter(r=>['Unmatched','Partially Matched','Exception'].includes(r['Reconciliation status'])),difference=rows.reduce((s,r)=>s+Number(r['Difference amount (SAR)']||0),0),closing=rows.length?Number(rows[0]['Statement closing balance (SAR)']||0):0;return {rows,reconciled,matched,exceptions,difference,closing}}
function bankControlPanel(){const c=bankReconciliationControl();return `<section class="bank-control-panel"><article class="card"><span>Statement lines</span><h3>${c.rows.length}</h3><small>Imported or entered bank lines</small></article><article class="card"><span>Reconciled lines</span><h3>${c.reconciled.length}</h3><small>${c.matched.length} matched / awaiting review</small></article><article class="card"><span>Open exceptions</span><h3 class="${c.exceptions.length?'validation-fail':'validation-pass'}">${c.exceptions.length}</h3><small>Unmatched, partial or exception</small></article><article class="card"><span>Unresolved difference</span><h3>${compactMoney(c.difference)}</h3><small>Statement closing balance ${compactMoney(c.closing)}</small></article></section>`}
