document.addEventListener('submit',e=>{if(e.target.id!=='entryForm'||e.target.dataset.formKey!=='Bank & Reconciliation')return;const data=Object.fromEntries(new FormData(e.target)),controlled=['Matched','Prepared for Review','Reconciled'].includes(data['Reconciliation status']),difference=Number(data['Difference amount (SAR)']||0);if(controlled&&(!data['Source bank transaction']||difference>.01)){e.preventDefault();e.stopImmediatePropagation();toast('Matched and reconciled bank lines require a source transaction and zero difference');return}if(data['Review status']==='Approved'&&data['Prepared / reconciled by']?.trim().toLowerCase()===data['Reviewed by']?.trim().toLowerCase()){e.preventDefault();e.stopImmediatePropagation();toast('Bank reconciliation preparer and reviewer must be different people')}},true);
const bankAuditV92=window.mustaqeemDemoAudit;
window.mustaqeemDemoAudit=function(){const result=bankAuditV92(),seen=new Set();recordsFor('Bank & Reconciliation').forEach(r=>{const key=`${r['Bank account / IBAN']}|${r['Statement number']}|${r['Statement line reference']}`;if(seen.has(key))result.issues.push(`${r['Document Number']}: duplicate bank statement line`);seen.add(key);if(['Matched','Prepared for Review','Reconciled'].includes(r['Reconciliation status'])&&Math.abs(Number(r['Difference amount (SAR)']||0))>.01)result.issues.push(`${r['Document Number']}: reconciled bank line has a non-zero difference`);if(r['Review status']==='Approved'&&r['Prepared / reconciled by']&&r['Prepared / reconciled by']===r['Reviewed by'])result.issues.push(`${r['Document Number']}: bank reconciliation lacks preparer/reviewer segregation`)});result.passed=result.issues.length===0;return result};

