function cashbookWorkspace(){const rows=voucherRecords(),accounts=[...new Set(rows.map(r=>r['Bank / cash account']||'Unassigned'))];return `<article class="card cash-bank-register"><div class="card-title"><div><p class="section-eyebrow">CASHBOOK AND BANKBOOK</p><h3>Account movement summary</h3></div><span class="badge">Live from vouchers</span></div><div class="table-wrap"><table><thead><tr><th>ACCOUNT</th><th>RECEIPTS</th><th>PAYMENTS</th><th>NET MOVEMENT</th><th>UNCLEARED</th></tr></thead><tbody>${accounts.length?accounts.map(account=>{const lines=rows.filter(r=>(r['Bank / cash account']||'Unassigned')===account),receipts=lines.filter(r=>['BRV','CRV'].includes(voucherCode(r))).reduce((s,r)=>s+Number(r['Amount (SAR)']||0),0),payments=lines.filter(r=>['BPV','CPV'].includes(voucherCode(r))).reduce((s,r)=>s+Number(r['Amount (SAR)']||0),0),uncleared=lines.filter(r=>!/Cleared|Reversed/.test(r.Status||'')).length;return `<tr><td><b>${account}</b></td><td>${compactMoney(receipts)}</td><td>${compactMoney(payments)}</td><td class="${receipts-payments<0?'validation-fail':'validation-pass'}">${compactMoney(receipts-payments)}</td><td>${uncleared}</td></tr>`}).join(''):'<tr><td colspan="5"><div class="empty-state">Post a BPV, BRV, CPV or CRV to build the books.</div></td></tr>'}</tbody></table></div></article>`}
