function configureEstimateTenderSelection(){
 const original=document.querySelector('[name="Select qualified contract"]');
 if(!original)return;
 const records=savedData(),estimates=records.filter(record=>record.form==='Cost Estimation & Scenarios'),used=new Set(estimates.map(record=>record['Source tender document']).filter(Boolean));
 const tenders=tenderRegisterRecords().filter(tender=>!used.has(tender['Document Number']));
 const select=document.createElement('select');
 select.name=original.name;
 select.required=true;
 select.innerHTML=`<option value="">${tenders.length?'Select an unused qualified tenderâ€¦':'No unused qualified tender is available'}</option>${tenders.map(tender=>`<option value="${tender['Source opportunity document']}" data-tender-document="${tender['Document Number']}">${tender['Document Number']} â€” ${tender['Contract number']||'Contract pending'} â€” ${tender['Prospective client']||'Client pending'}</option>`).join('')}`;
 original.replaceWith(select);
 select.closest('label')?.querySelector('.field-help')?.replaceChildren(document.createTextNode('Only tenders created from Director-qualified opportunities are available.'));
 const tenderReference=document.querySelector('[name="Tender / estimation reference"]');
 select.addEventListener('change',()=>{
  const option=select.selectedOptions[0],tender=tenders.find(row=>row['Document Number']===option?.dataset.tenderDocument);
  if(!tender)return;
  if(tenderReference&&!tenderReference.value)tenderReference.value=tender['Tender reference']||tender['Document Number'];
  setFormValue('Expected contract revenue (SAR)',tender['Estimated contract value (SAR)']);
  applyContractTypeCostRules(select);
  let hidden=document.querySelector('[name="Source tender document"]');
  if(!hidden){hidden=document.createElement('input');hidden.type='hidden';hidden.name='Source tender document';document.getElementById('entryForm').appendChild(hidden)}
 hidden.value=tender['Document Number'];
 });
}

