function ensureProjectCostCentreMaster(project){
 if(!project)return;
 const records=savedData(),source=project['Document Number'];
 if(records.some(record=>record.module==='settings'&&record.form==='Projects & Cost Centres'&&record['Source awarded project']===source))return;
 const activeCompany=localStorage.getItem('mustaqeem-active-company')||'Elevate Builders';
 records.push({
  module:'settings',form:'Projects & Cost Centres',createdAt:new Date().toISOString(),
  'Document Number':`SET-PRJ-${new Date().getFullYear()}-${String(records.filter(record=>record.module==='settings'&&record.form==='Projects & Cost Centres').length+1).padStart(5,'0')}`,
  'Source awarded project':source,
  'Project / cost centre code':project['Project code']||source,
  'Project / cost centre name':project['Project name']||source,
  'Record type':'Project','Company / entity':activeCompany,
  'Project manager / owner':project['Project manager']||'',
  'Start date':project['Start date']||project['Expected start date']||'',
  'End date':project['Completion date']||'',
  'Posting allowed':'Yes','Active':'Yes'
 });
 localStorage.setItem('mustaqeem-demo-records',JSON.stringify(records));
}

